import{_ as t,o as a,c as o,ae as i}from"./chunks/framework.BD9pLfSD.js";const g=JSON.parse('{"title":"Roadmap: Next Steps (Jan 20 - Feb 1)","description":"","frontmatter":{},"headers":[],"relativePath":"docs/plans/ROADMAP_NEXT_STEPS.md","filePath":"docs/plans/ROADMAP_NEXT_STEPS.md"}'),r={name:"docs/plans/ROADMAP_NEXT_STEPS.md"};function n(s,e,l,d,c,u){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="roadmap-next-steps-jan-20-feb-1" tabindex="-1">Roadmap: Next Steps (Jan 20 - Feb 1) <a class="header-anchor" href="#roadmap-next-steps-jan-20-feb-1" aria-label="Permalink to &quot;Roadmap: Next Steps (Jan 20 - Feb 1)&quot;">​</a></h1><h2 id="strategic-shift-devnet-first" tabindex="-1">Strategic Shift: Devnet-First <a class="header-anchor" href="#strategic-shift-devnet-first" aria-label="Permalink to &quot;Strategic Shift: Devnet-First&quot;">​</a></h2><p>Due to persistent instability with the local Light Protocol validator environment (specifically dependency downloads), development will shift strategy:</p><ol><li><strong>Local Logic Validation:</strong> Unit tests for Rust contracts (Gateway/Receipts) will run locally without the full validator stack where possible.</li><li><strong>Devnet Deployment:</strong> Integration testing will move directly to Solana Devnet using public RPCs (Helius/Light) to bypass local infrastructure issues.</li></ol><h2 id="_1-core-logic-refinement-days-1-3" tabindex="-1">1. Core Logic Refinement (Days 1-3) <a class="header-anchor" href="#_1-core-logic-refinement-days-1-3" aria-label="Permalink to &quot;1. Core Logic Refinement (Days 1-3)&quot;">​</a></h2><p><strong>Goal:</strong> Solidify the Rust contracts so they are ready for Devnet.</p><h3 id="gateway-program-xb77-gateway" tabindex="-1">Gateway Program (xb77_gateway) <a class="header-anchor" href="#gateway-program-xb77-gateway" aria-label="Permalink to &quot;Gateway Program (xb77_gateway)&quot;">​</a></h3><ul><li>[ ] <strong>Instruction hardening:</strong> Ensure <code>verify_badge</code> and <code>submit_private_order</code> validate inputs strictly.</li><li>[ ] <strong>State Management:</strong> Finalize the PDA structure for <code>GatewayState</code> and <code>OrderState</code>.</li><li>[ ] <strong>Unit Tests:</strong> Write Rust unit tests (<code>cargo test</code>) to verify logic isolated from the chain.</li></ul><h3 id="receipts-program-xb77-receipts" tabindex="-1">Receipts Program (xb77_receipts) <a class="header-anchor" href="#receipts-program-xb77-receipts" aria-label="Permalink to &quot;Receipts Program (xb77_receipts)&quot;">​</a></h3><ul><li>[ ] <strong>Compression Logic:</strong> Implement the CPI call to Light Protocol&#39;s system program (even if mocked locally).</li><li>[ ] <strong>Structure:</strong> Define the <code>CompressedReceipt</code> struct (Vendor, Item, Amount, Hash) clearly in Rust.</li></ul><h2 id="_2-sdk-development-days-3-5" tabindex="-1">2. SDK Development (Days 3-5) <a class="header-anchor" href="#_2-sdk-development-days-3-5" aria-label="Permalink to &quot;2. SDK Development (Days 3-5)&quot;">​</a></h2><p><strong>Goal:</strong> Build the client-side bridge (<code>@xb77/sdk</code>) to interact with the programs.</p><h3 id="identity-module" tabindex="-1">Identity Module <a class="header-anchor" href="#identity-module" aria-label="Permalink to &quot;Identity Module&quot;">​</a></h3><ul><li>[ ] Wrap Noir proof generation (<code>generate_badge_proof.ts</code>) into a clean SDK method: <code>sdk.identity.prove()</code>.</li></ul><h3 id="payment-module-worktree-a" tabindex="-1">Payment Module (Worktree A) <a class="header-anchor" href="#payment-module-worktree-a" aria-label="Permalink to &quot;Payment Module (Worktree A)&quot;">​</a></h3><ul><li>[ ] Integrate Arcium/USD1 SDK headers.</li><li>[ ] Implement <code>sdk.payment.transfer_private(amount, recipient)</code>.</li></ul><h3 id="audit-module-worktree-b" tabindex="-1">Audit Module (Worktree B) <a class="header-anchor" href="#audit-module-worktree-b" aria-label="Permalink to &quot;Audit Module (Worktree B)&quot;">​</a></h3><ul><li>[ ] Implement <code>sdk.audit.fetch_receipts()</code> using Light Protocol&#39;s DAS (Data Availability Service) API.</li><li>[ ] Implement <code>sdk.audit.verify_receipt(hash)</code>.</li></ul><h2 id="_3-devnet-integration-days-5-8" tabindex="-1">3. Devnet Integration (Days 5-8) <a class="header-anchor" href="#_3-devnet-integration-days-5-8" aria-label="Permalink to &quot;3. Devnet Integration (Days 5-8)&quot;">​</a></h2><p><strong>Goal:</strong> Connect the pieces on the live test network.</p><ul><li>[ ] <strong>Deploy Gateway:</strong> Deploy <code>xb77_gateway</code> to Devnet.</li><li>[ ] <strong>Config:</strong> Initialize Gateway with the Devnet Verifier address.</li><li>[ ] <strong>End-to-End Test:</strong> Run a script that: <ol><li>Generates a Noir Proof.</li><li>Submits it to the Devnet Gateway.</li><li>Gateway validates and triggers a &quot;Mock Transfer&quot; (or real if Arcium is ready).</li><li>Gateway emits a &quot;Mock Receipt&quot; (or real compressed if Light Devnet is stable).</li></ol></li></ul><h2 id="_4-ui-demo-polish-days-9-10" tabindex="-1">4. UI &amp; Demo Polish (Days 9-10) <a class="header-anchor" href="#_4-ui-demo-polish-days-9-10" aria-label="Permalink to &quot;4. UI &amp; Demo Polish (Days 9-10)&quot;">​</a></h2><p><strong>Goal:</strong> Visuals for the Hackathon submission.</p><ul><li>[ ] <strong>CLI Dashboard:</strong> A simple terminal UI showing &quot;Private Balance&quot; vs &quot;Public View&quot;.</li><li>[ ] <strong>Demo Video:</strong> Record the flow: &quot;Agent generates proof -&gt; Gateway accepts -&gt; Private Transfer happens&quot;.</li></ul><h2 id="contingencies" tabindex="-1">Contingencies <a class="header-anchor" href="#contingencies" aria-label="Permalink to &quot;Contingencies&quot;">​</a></h2><ul><li><strong>If Light Devnet fails:</strong> We will store &quot;Encrypted Logs&quot; in standard Solana accounts as a fallback for the receipts, preserving the privacy narrative even if compression is mocked.</li><li><strong>If Arcium Devnet fails:</strong> We will use a standard SPL Token Transfer with a &quot;Mixer&quot; pattern (simulated privacy) for the demo.</li></ul>',26)])])}const p=t(r,[["render",n]]);export{g as __pageData,p as default};
